77→export function createDimension(overrides = {}) {
78→  return createPartBase('dimension', {
79→    name: 'Dimension',
80→    startPoint: { x: 0, y: 0, z: 0, ...overrides.startPoint },
81→    endPoint: { x: 0, y: 0, z: 0, ...overrides.endPoint },
82→    offset: 200,
83→    textOverride: null,
84→    boundPartId: null,
85→    boundProperty: null,
86→    boundAxis: null,
87→    fill: 'none',
88→    stroke: '#1E2433',
89→    ...overrides,
90→  });
91→}
