 1→import { createPanel, createLeg } from './partModels';
 2→import { createAssembly } from './assemblyModels';
 3→
 4→export function buildDemoTable() {
 5→  const assembly = createAssembly('Office Desk', { category: 'table' });
 6→
 7→  // Tabletop: 1200×600mm panel at z=720 (on top of legs)
 8→  const tabletop = createPanel({
 9→    name: 'Tabletop',
10→    width: 1200,
11→    depth: 600,
12→    thickness: 18,
13→    material: 'plywood',
14→    position: { x: 0, y: 0, z: 720 },
15→    fill: 'rgba(184, 134, 11, 0.06)',
16→  });
17→
18→  const inset = 30;
19→  const legW = 40;
20→  const legD = 40;
21→  const legH = 720;
22→
23→  const legTL = createLeg({
24→    name: 'Leg TL',
25→    width: legW, depth: legD, height: legH,
26→    position: { x: inset, y: inset, z: 0 },
27→  });
28→
29→  const legTR = createLeg({
30→    name: 'Leg TR',
31→    width: legW, depth: legD, height: legH,
32→    position: { x: 1200 - inset - legW, y: inset, z: 0 },
33→  });
34→
35→  const legBL = createLeg({
36→    name: 'Leg BL',
37→    width: legW, depth: legD, height: legH,
38→    position: { x: inset, y: 600 - inset - legD, z: 0 },
39→  });
40→
41→  const legBR = createLeg({
42→    name: 'Leg BR',
43→    width: legW, depth: legD, height: legH,
44→    position: { x: 1200 - inset - legW, y: 600 - inset - legD, z: 0 },
45→  });
46→
47→  const parts = [tabletop, legTL, legTR, legBL, legBR];
48→  assembly.partIds = parts.map((p) => p.id);
49→  for (const part of parts) {
50→    part.assemblyId = assembly.id;
51→  }
52→
53→  return { assembly, parts };
54→}
