  1→import { createContext, useContext, useReducer, useCallback } from 'react';
  2→import { createSketchProject } from '../domain/sketchModels';
  3→import { sanitizePartDimensions, sanitizePartPosition } from '../domain/validation';
  4→import { resolveConstraints } from '../domain/constraintResolver';
  5→import { updateBoundDimensionEndpoints } from '../domain/dimensionBinding';
  6→import { generateId } from '@/domain/ids';
  7→
  8→const SketchContext = createContext(null);
  9→const HISTORY_LIMIT = 80;
 10→
 11→function snapshotSketch(sketchProject) {
 12→  return JSON.stringify(sketchProject);
 13→}
 14→
 15→function applyUpdate(state, nextProject, recordHistory = true) {
 16→  const nextSnapshot = snapshotSketch(nextProject);
 17→  const history = recordHistory
 18→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 19→    : state.history;
 20→
 21→  return {
 22→    ...state,
 23→    history,
 24→    future: recordHistory ? [] : state.future,
 25→    project: nextProject,
 26→    isDirty: nextSnapshot !== state.savedSnapshot,
 27→  };
 28→}
 29→
 30→function mergePart(existing, updates) {
 31→  const merged = { ...existing, ...updates };
 32→  // Deep-merge position and rotation
 33→  if (updates.position) {
 34→    merged.position = { ...existing.position, ...updates.position };
 35→  }
 36→  if (updates.rotation) {
 37→    merged.rotation = { ...existing.rotation, ...updates.rotation };
 38→  }
 39→  return merged;
 40→}
 41→
 42→function sanitizePart(part) {
 43→  if (part.type === 'dimension') return part;
 44→  return sanitizePartPosition(sanitizePartDimensions(part));
 45→}
 46→
 47→function applyConstraints(project) {
 48→  const constraints = project.constraints || [];
 49→  if (constraints.length === 0) return project;
 50→
 51→  const resolved = resolveConstraints(constraints, project.parts);
 52→  if (resolved.size === 0) return project;
 53→
 54→  return {
 55→    ...project,
 56→    parts: project.parts.map((p) => {
 57→      const newPos = resolved.get(p.id);
 58→      return newPos ? { ...p, position: newPos } : p;
 59→    }),
 60→  };
 61→}
 62→
 63→function updateBoundDimensions(project, updatedPartId) {
 64→  const updatedPart = project.parts.find((p) => p.id === updatedPartId);
 65→  if (!updatedPart) return project;
 66→
 67→  let changed = false;
 68→  const newParts = project.parts.map((p) => {
 69→    if (p.type === 'dimension' && p.boundPartId === updatedPartId) {
 70→      changed = true;
 71→      return updateBoundDimensionEndpoints(p, updatedPart);
 72→    }
 73→    return p;
 74→  });
 75→
 76→  return changed ? { ...project, parts: newParts } : project;
 77→}
 78→
 79→function clonePart(part, idMap) {
 80→  const newId = generateId('part');
 81→  idMap.set(part.id, newId);
 82→  return {
 83→    ...part,
 84→    id: newId,
 85→    name: `${part.name} (copy)`,
 86→    position: {
 87→      ...part.position,
 88→      x: part.position.x + 50,
 89→      y: part.position.y + 50,
 90→    },
 91→  };
 92→}
 93→
 94→function sketchReducer(state, action) {
 95→  switch (action.type) {
 96→    case 'SKETCH_NEW': {
 97→      const newProject = action.project || createSketchProject();
 98→      return {
 99→        project: newProject,
100→        isDirty: false,
101→        savedSnapshot: snapshotSketch(newProject),
102→        history: [],
103→        future: [],
104→      };
105→    }
106→
107→    case 'SKETCH_LOAD': {
108→      const loaded = action.project;
109→      return {
110→        project: loaded,
111→        isDirty: false,
112→        savedSnapshot: snapshotSketch(loaded),
113→        history: [],
114→        future: [],
115→      };
116→    }
117→
118→    case 'PART_ADD': {
119→      const part = sanitizePart(action.part);
120→      let nextProject = {
121→        ...state.project,
122→        updatedAt: new Date().toISOString(),
123→        parts: [...state.project.parts, part],
124→      };
125→      nextProject = applyConstraints(nextProject);
126→      return applyUpdate(state, nextProject);
127→    }
128→
129→    case 'PART_UPDATE': {
130→      let nextProject = {
131→        ...state.project,
132→        updatedAt: new Date().toISOString(),
133→        parts: state.project.parts.map((p) => {
134→          if (p.id !== action.part.id) return p;
135→          const merged = mergePart(p, action.part);
136→          return merged.type === 'dimension' ? merged : sanitizePart(merged);
137→        }),
138→      };
139→      nextProject = applyConstraints(nextProject);
140→      nextProject = updateBoundDimensions(nextProject, action.part.id);
141→      return applyUpdate(state, nextProject);
142→    }
143→
144→    case 'PART_DELETE': {
145→      const partId = action.partId;
146→      // Also remove child parts (cutouts/holes with this parentId)
147→      const childIds = new Set(
148→        state.project.parts.filter((p) => p.parentId === partId).map((p) => p.id)
149→      );
150→      const idsToRemove = new Set([partId, ...childIds]);
151→
152→      // Also remove constraints referencing deleted parts
153→      const constraints = (state.project.constraints || []).filter(
154→        (c) => !idsToRemove.has(c.sourcePartId) && !idsToRemove.has(c.targetPartId)
155→      );
156→
157→      // Also remove dimensions bound to deleted parts
158→      return applyUpdate(state, {
159→        ...state.project,
160→        updatedAt: new Date().toISOString(),
161→        parts: state.project.parts
162→          .filter((p) => !idsToRemove.has(p.id))
163→          .map((p) => {
164→            if (p.type === 'dimension' && p.boundPartId && idsToRemove.has(p.boundPartId)) {
165→              return { ...p, boundPartId: null, boundProperty: null, boundAxis: null };
166→            }
167→            return p;
168→          }),
169→        assemblies: state.project.assemblies.map((asm) => ({
170→          ...asm,
171→          partIds: asm.partIds.filter((id) => !idsToRemove.has(id)),
172→        })),
173→        constraints,
174→      });
175→    }
176→
177→    case 'PART_CLONE': {
178→      const partId = action.partId;
179→      const part = state.project.parts.find((p) => p.id === partId);
180→      if (!part) return state;
181→
182→      const idMap = new Map();
183→      const cloned = clonePart(part, idMap);
184→
185→      // Clone children (cutouts/holes with matching parentId)
186→      const children = state.project.parts.filter((p) => p.parentId === partId);
187→      const clonedChildren = children.map((child) => {
188→        const clonedChild = clonePart(child, idMap);
189→        clonedChild.parentId = cloned.id;
190→        return clonedChild;
191→      });
192→
193→      const newParts = [cloned, ...clonedChildren];
194→
195→      // Add to same assembly if applicable
196→      let assemblies = state.project.assemblies;
197→      if (part.assemblyId) {
198→        assemblies = assemblies.map((asm) => {
199→          if (asm.id === part.assemblyId) {
200→            return {
201→              ...asm,
202→              partIds: [...asm.partIds, ...newParts.map((p) => p.id)],
203→            };
204→          }
205→          return asm;
206→        });
207→        // Set assemblyId on clones
208→        for (const np of newParts) {
209→          np.assemblyId = part.assemblyId;
210→        }
211→      }
212→
213→      return applyUpdate(state, {
214→        ...state.project,
215→        updatedAt: new Date().toISOString(),
216→        parts: [...state.project.parts, ...newParts],
217→        assemblies,
218→      });
219→    }
220→
221→    case 'ASSEMBLY_ADD':
222→      return applyUpdate(state, {
223→        ...state.project,
224→        updatedAt: new Date().toISOString(),
225→        assemblies: [...state.project.assemblies, action.assembly],
226→      });
227→
228→    case 'ASSEMBLY_UPDATE':
229→      return applyUpdate(state, {
230→        ...state.project,
231→        updatedAt: new Date().toISOString(),
232→        assemblies: state.project.assemblies.map((asm) =>
233→          asm.id === action.assembly.id ? { ...asm, ...action.assembly } : asm
234→        ),
235→      });
236→
237→    case 'ASSEMBLY_DELETE': {
238→      const asmId = action.assemblyId;
239→      return applyUpdate(state, {
240→        ...state.project,
241→        updatedAt: new Date().toISOString(),
242→        assemblies: state.project.assemblies.filter((asm) => asm.id !== asmId),
243→        parts: state.project.parts.map((p) =>
244→          p.assemblyId === asmId ? { ...p, assemblyId: null } : p
245→        ),
246→      });
247→    }
248→
249→    case 'ASSEMBLY_ADD_PART': {
250→      const { assemblyId, partId } = action;
251→      return applyUpdate(state, {
252→        ...state.project,
253→        updatedAt: new Date().toISOString(),
254→        assemblies: state.project.assemblies.map((asm) =>
255→          asm.id === assemblyId && !asm.partIds.includes(partId)
256→            ? { ...asm, partIds: [...asm.partIds, partId] }
257→            : asm
258→        ),
259→        parts: state.project.parts.map((p) =>
260→          p.id === partId ? { ...p, assemblyId } : p
261→        ),
262→      });
263→    }
264→
265→    case 'ASSEMBLY_REMOVE_PART': {
266→      const { assemblyId, partId } = action;
267→      return applyUpdate(state, {
268→        ...state.project,
269→        updatedAt: new Date().toISOString(),
270→        assemblies: state.project.assemblies.map((asm) =>
271→          asm.id === assemblyId
272→            ? { ...asm, partIds: asm.partIds.filter((id) => id !== partId) }
273→            : asm
274→        ),
275→        parts: state.project.parts.map((p) =>
276→          p.id === partId && p.assemblyId === assemblyId ? { ...p, assemblyId: null } : p
277→        ),
278→      });
279→    }
280→
281→    case 'ASSEMBLY_CLONE': {
282→      const asmId = action.assemblyId;
283→      const asm = state.project.assemblies.find((a) => a.id === asmId);
284→      if (!asm) return state;
285→
286→      const idMap = new Map();
287→      const newAsmId = generateId('asm');
288→      const newAsm = {
289→        ...asm,
290→        id: newAsmId,
291→        name: `${asm.name} (copy)`,
292→        partIds: [],
293→      };
294→
295→      // Clone all parts in this assembly
296→      const asmParts = state.project.parts.filter((p) => p.assemblyId === asmId);
297→      const clonedParts = [];
298→
299→      for (const part of asmParts) {
300→        const cloned = clonePart(part, idMap);
301→        cloned.assemblyId = newAsmId;
302→        clonedParts.push(cloned);
303→      }
304→
305→      // Fix parentId references
306→      for (const cp of clonedParts) {
307→        if (cp.parentId && idMap.has(cp.parentId)) {
308→          cp.parentId = idMap.get(cp.parentId);
309→        }
310→      }
311→
312→      newAsm.partIds = clonedParts.map((p) => p.id);
313→
314→      return applyUpdate(state, {
315→        ...state.project,
316→        updatedAt: new Date().toISOString(),
317→        parts: [...state.project.parts, ...clonedParts],
318→        assemblies: [...state.project.assemblies, newAsm],
319→      });
320→    }
321→
322→    case 'CONSTRAINT_ADD': {
323→      const constraints = [...(state.project.constraints || []), action.constraint];
324→      let nextProject = {
325→        ...state.project,
326→        updatedAt: new Date().toISOString(),
327→        constraints,
328→      };
329→      nextProject = applyConstraints(nextProject);
330→      return applyUpdate(state, nextProject);
331→    }
332→
333→    case 'CONSTRAINT_UPDATE': {
334→      const constraints = (state.project.constraints || []).map((c) =>
335→        c.id === action.constraint.id ? { ...c, ...action.constraint } : c
336→      );
337→      let nextProject = {
338→        ...state.project,
339→        updatedAt: new Date().toISOString(),
340→        constraints,
341→      };
342→      nextProject = applyConstraints(nextProject);
343→      return applyUpdate(state, nextProject);
344→    }
345→
346→    case 'CONSTRAINT_DELETE': {
347→      const constraints = (state.project.constraints || []).filter(
348→        (c) => c.id !== action.constraintId
349→      );
350→      return applyUpdate(state, {
351→        ...state.project,
352→        updatedAt: new Date().toISOString(),
353→        constraints,
354→      });
355→    }
356→
357→    case 'ANNOTATION_ADD':
358→      return applyUpdate(state, {
359→        ...state.project,
360→        updatedAt: new Date().toISOString(),
361→        annotations: [...(state.project.annotations || []), action.annotation],
362→      });
363→
364→    case 'ANNOTATION_UPDATE':
365→      return applyUpdate(state, {
366→        ...state.project,
367→        updatedAt: new Date().toISOString(),
368→        annotations: (state.project.annotations || []).map((a) =>
369→          a.id === action.annotation.id ? { ...a, ...action.annotation } : a
370→        ),
371→      });
372→
373→    case 'ANNOTATION_DELETE':
374→      return applyUpdate(state, {
375→        ...state.project,
376→        updatedAt: new Date().toISOString(),
377→        annotations: (state.project.annotations || []).filter((a) => a.id !== action.annotationId),
378→      });
379→
380→    case 'PROJECT_UPDATE_META':
381→      return applyUpdate(state, {
382→        ...state.project,
383→        updatedAt: new Date().toISOString(),
384→        ...action.meta,
385→      });
386→
387→    case 'SKETCH_SHEET_ADD':
388→      return applyUpdate(state, {
389→        ...state.project,
390→        updatedAt: new Date().toISOString(),
391→        sheets: [...(state.project.sheets || []), action.sheet],
392→      });
393→
394→    case 'SKETCH_SHEET_UPDATE':
395→      return applyUpdate(state, {
396→        ...state.project,
397→        updatedAt: new Date().toISOString(),
398→        sheets: (state.project.sheets || []).map((s) =>
399→          s.id === action.sheet.id ? { ...s, ...action.sheet } : s
400→        ),
401→      });
402→
403→    case 'SKETCH_SHEET_DELETE':
404→      return applyUpdate(state, {
405→        ...state.project,
406→        updatedAt: new Date().toISOString(),
407→        sheets: (state.project.sheets || []).filter((s) => s.id !== action.sheetId),
408→      });
409→
410→    case 'SKETCH_SHEET_VIEWPORT_ADD': {
411→      const targetSheet = (state.project.sheets || []).find((s) => s.id === action.sheetId);
412→      if (!targetSheet) return state;
413→      return applyUpdate(state, {
414→        ...state.project,
415→        updatedAt: new Date().toISOString(),
416→        sheets: state.project.sheets.map((s) =>
417→          s.id === action.sheetId
418→            ? { ...s, viewports: [...(s.viewports || []), action.viewport] }
419→            : s
420→        ),
421→      });
422→    }
423→
424→    case 'SKETCH_SHEET_VIEWPORT_UPDATE': {
425→      return applyUpdate(state, {
426→        ...state.project,
427→        updatedAt: new Date().toISOString(),
428→        sheets: (state.project.sheets || []).map((s) =>
429→          s.id === action.sheetId
430→            ? {
431→                ...s,
432→                viewports: (s.viewports || []).map((vp) =>
433→                  vp.id === action.viewport.id ? { ...vp, ...action.viewport } : vp
434→                ),
435→              }
436→            : s
437→        ),
438→      });
439→    }
440→
441→    case 'SKETCH_SHEET_VIEWPORT_DELETE':
442→      return applyUpdate(state, {
443→        ...state.project,
444→        updatedAt: new Date().toISOString(),
445→        sheets: (state.project.sheets || []).map((s) =>
446→          s.id === action.sheetId
447→            ? { ...s, viewports: (s.viewports || []).filter((vp) => vp.id !== action.viewportId) }
448→            : s
449→        ),
450→      });
451→
452→    case 'UNDO': {
453→      if (state.history.length === 0) return state;
454→      const previous = state.history[state.history.length - 1];
455→      return {
456→        ...state,
457→        project: previous,
458→        history: state.history.slice(0, -1),
459→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
460→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
461→      };
462→    }
463→
464→    case 'REDO': {
465→      if (state.future.length === 0) return state;
466→      const next = state.future[0];
467→      return {
468→        ...state,
469→        project: next,
470→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
471→        future: state.future.slice(1),
472→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
473→      };
474→    }
475→
476→    case 'MARK_SAVED':
477→      return {
478→        ...state,
479→        isDirty: false,
480→        savedSnapshot: snapshotSketch(state.project),
481→      };
482→
483→    default:
484→      return state;
485→  }
486→}
487→
488→function createInitialState(project) {
489→  return {
490→    project,
491→    isDirty: false,
492→    savedSnapshot: snapshotSketch(project),
493→    history: [],
494→    future: [],
495→  };
496→}
497→
498→export function SketchProvider({ children, initialProject }) {
499→  const [state, dispatch] = useReducer(
500→    sketchReducer,
501→    initialProject || createSketchProject(),
502→    createInitialState
503→  );
504→
505→  return (
506→    <SketchContext.Provider value={{ state, dispatch }}>
507→      {children}
508→    </SketchContext.Provider>
509→  );
510→}
511→
512→export function useSketch() {
513→  const ctx = useContext(SketchContext);
514→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
515→  const { state, dispatch } = ctx;
516→
517→  const getPart = useCallback(
518→    (partId) => state.project.parts.find((p) => p.id === partId) || null,
519→    [state.project.parts]
520→  );
521→
522→  const getAssembly = useCallback(
523→    (assemblyId) => state.project.assemblies.find((a) => a.id === assemblyId) || null,
524→    [state.project.assemblies]
525→  );
526→
527→  const getPartsForAssembly = useCallback(
528→    (assemblyId) => state.project.parts.filter((p) => p.assemblyId === assemblyId),
529→    [state.project.parts]
530→  );
531→
532→  const getChildParts = useCallback(
533→    (parentId) => state.project.parts.filter((p) => p.parentId === parentId),
534→    [state.project.parts]
535→  );
536→
537→  return {
538→    project: state.project,
539→    isDirty: state.isDirty,
540→    canUndo: state.history.length > 0,
541→    canRedo: state.future.length > 0,
542→    dispatch,
543→    getPart,
544→    getAssembly,
545→    getPartsForAssembly,
546→    getChildParts,
547→  };
548→}
