127→export default function SketchSidebar() {
128→  const { project, dispatch, getPartsForAssembly } = useSketch();
129→  const { activeAssemblyId, selectedId, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
130→
131→  const [expandedIds, setExpandedIds] = useState(new Set());
132→
133→  const assemblies = project.assemblies || [];
134→  const allParts = project.parts.filter((p) => p.type !== 'dimension');
135→
136→  // Build part tree: group by assembly, then nest children under parents
137→  const toggleExpand = (id) => {
138→    setExpandedIds((prev) => {
139→      const next = new Set(prev);
140→      if (next.has(id)) next.delete(id);
141→      else next.add(id);
142→      return next;
143→    });
144→  };
145→
146→  const handleAddAssembly = () => {
147→    const asm = createAssembly(`Assembly ${assemblies.length + 1}`);
148→    dispatch({ type: 'ASSEMBLY_ADD', assembly: asm });
149→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: asm.id });
150→  };
151→
152→  const handleSelectAssembly = (assemblyId) => {
153→    if (workspaceMode === 'sheet') {
154→      editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
155→    }
156→    editorDispatch({
157→      type: 'SET_ACTIVE_ASSEMBLY',
158→      assemblyId: activeAssemblyId === assemblyId ? null : assemblyId,
159→    });
160→  };
161→
162→  const handleDeleteAssembly = (e, assemblyId) => {
163→    e.stopPropagation();
164→    dispatch({ type: 'ASSEMBLY_DELETE', assemblyId });
165→    if (activeAssemblyId === assemblyId) {
166→      editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
167→    }
168→  };
169→
170→  const handleCloneAssembly = (e, assemblyId) => {
171→    e.stopPropagation();
172→    dispatch({ type: 'ASSEMBLY_CLONE', assemblyId });
173→  };
174→
175→  const handleSelectPart = (partId) => {
176→    if (workspaceMode === 'sheet') {
177→      editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
178→    }
179→    editorDispatch({ type: 'SELECT_OBJECT', id: partId, objectType: 'part' });
180→  };
181→
182→  const handleDeletePart = (partId) => {
183→    dispatch({ type: 'PART_DELETE', partId });
184→    if (selectedId === partId) {
185→      editorDispatch({ type: 'DESELECT' });
186→    }
187→  };
188→
189→  const handleClonePart = (partId) => {
190→    dispatch({ type: 'PART_CLONE', partId });
191→  };
192→
193→  // Build tree for a given set of parts
194→  function renderPartTree(parts, depth = 0) {
195→    const topLevel = parts.filter((p) => !p.parentId || !parts.some((pp) => pp.id === p.parentId));
196→    return topLevel.map((part) => {
197→      const children = parts.filter((p) => p.parentId === part.id);
198→      return (
199→        <div key={part.id}>
200→          <PartItem
201→            part={part}
202→            isSelected={part.id === selectedId}
203→            depth={depth}
204→            onSelect={handleSelectPart}
205→            onDelete={handleDeletePart}
206→            onClone={handleClonePart}
207→          />
208→          {children.length > 0 && children.map((child) => (
209→            <PartItem
210→              key={child.id}
211→              part={child}
212→              isSelected={child.id === selectedId}
213→              depth={depth + 1}
214→              onSelect={handleSelectPart}
215→              onDelete={handleDeletePart}
216→              onClone={handleClonePart}
217→            />
218→          ))}
219→        </div>
220→      );
221→    });
222→  }
223→
224→  // Unassigned parts: no assemblyId
225→  const unassignedParts = allParts.filter((p) => !p.assemblyId);
226→  const sheets = project.sheets || [];
227→
228→  const handleAddSheet = () => {
229→    const sheet = createSheet(`Sheet ${sheets.length + 1}`, {
230→      number: `S${String(sheets.length + 1).padStart(2, '0')}`,
231→      drawingName: `Sheet ${sheets.length + 1}`,
232→    });
233→    dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
234→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
235→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
236→  };
237→
238→  const handleSelectSheet = (sheetId) => {
239→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId });
240→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
241→  };
242→
243→  const handleDeleteSheet = (e, sheetId) => {
244→    e.stopPropagation();
245→    dispatch({ type: 'SKETCH_SHEET_DELETE', sheetId });
246→    if (activeSheetId === sheetId) {
247→      editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
248→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
249→    }
250→  };
251→
252→  const handleGenerateAssemblySheet = (e, assemblyId) => {
253→    e.stopPropagation();
